import React from 'react';
import clsx from 'clsx';

export interface PanelContentProps {
  isActive?: boolean;
  style?: React.CSSProperties;
  className?: string;
  forceRender?: boolean;
  prefixCls?: string;
  role?: string;
}

type PanelContentActualProps = React.PropsWithChildren<PanelContentProps>;

export const PanelContent = React.forwardRef<HTMLDivElement, PanelContentActualProps>((props, ref) => {
  const { isActive, style, className, forceRender, children, prefixCls, role } = props;
  const [rendered, setRendered] = React.useState(isActive || forceRender);

  React.useEffect(() => {
    if (forceRender || isActive) {
      setRendered(true);
    }
  }, [forceRender, isActive]);

  if (!rendered) {
    return null;
  }
  return (
    <div style={style} className={clsx(`${prefixCls}-content`, className)} ref={ref} role={role}>
      <div className={`${prefixCls}-content-box`}>{children}</div>
    </div>
  );
});
